class Solution {
public:
    int flipLights(int n, int p) {
        if(!p) return 1; p=min(p,3); n=min(n,3);
        set<int> st={0};
        for(int t=0;t<p;t++){
            set<int> nx;
            for(int s:st) for(int op=0;op<4;op++){
                int a=s;
                if(op==0) a^=7;
                else if(op==1) a^=6;
                else if(op==2) a^=5;
                else a^=3;
                nx.insert(a&( (1<<n)-1 ));
            }
            st=nx;
        }
        return st.size();
    }
};
